private static (Dictionary<string, string> Aliases, Dictionary<string, List<string>> Fallbacks)
    ResolveTiers(ISet<string> presentKeys, IReadOnlyDictionary<string, string>? overrides = null)
{
    var aliases = new Dictionary<string, string>();
    var fallbacks = new Dictionary<string, List<string>>();

    foreach (var (tier, candidates) in Chains)
    {
        // Claude is opt-in premium: omit entirely when key is absent.
        if (tier == "claude" && !presentKeys.Contains("ANTHROPIC_API_KEY"))
            continue;

        // --- Override path ---
        if (overrides is not null && overrides.TryGetValue(tier, out var ov))
        {
            var ovKey = GetRequiredKey(ov);
            if (presentKeys.Contains(ovKey))
            {
                // Override wins: alias = ov, fallbacks = chain survivors
                // (excluding ov itself), still terminating in fallback.
                var survivors = candidates
                    .Where(c => presentKeys.Contains(c.RequiredKey))
                    .Select(c => c.Model)
                    .Where(m => m != ov)
                    .ToList();

                aliases[tier] = ov;

                if (survivors.Count > 0)
                {
                    // Skip the hf-qwen3-coder-next alias indirection.
                    if (tier != FallbackTier && survivors[0] == FallbackFloorModel)
                        survivors.RemoveAt(0);

                    // Non-claude chains must terminate in fallback.
                    if (tier != "claude" && (survivors.Count == 0 || survivors[^1] != FallbackTier))
                        survivors.Add(FallbackTier);

                    if (survivors.Count > 0)
                        fallbacks[tier] = survivors;
                }
                else if (tier != "claude")
                {
                    fallbacks[tier] = [FallbackTier];
                }

                continue;
            }
            // Key absent → ignore override, fall through to auto-resolve.
        }

        var chain = candidates
            .Where(c => presentKeys.Contains(c.RequiredKey))
            .Select(c => c.Model)
            .ToList();

        // Degenerate: no key at all. Still produce a valid alias so the
        // proxy boots (the model defs exist, just no api_key value).
        if (chain.Count == 0)
        {
            if (tier == "claude") continue;
            aliases[tier] = tier == FallbackTier ? FallbackFloorModel : FallbackTier;
            fallbacks[tier] = [FallbackTier];
            continue;
        }

        // When the first surviving model for a non-fallback tier is the
        // HF floor model itself, point the alias at the "fallback" tier
        // directly so the floor is always reached through one indirection.
        string alias;
        int chainStart;
        if (tier != FallbackTier && chain[0] == FallbackFloorModel)
        {
            alias = FallbackTier;
            chainStart = 1; // hf-qwen3-coder-next is reachable via fallback
        }
        else
        {
            alias = chain[0];
            chainStart = 1;
        }

        aliases[tier] = alias;

        var fb = chain.Skip(chainStart).ToList();

        // Every non-claude chain must terminate in the fallback tier.
        if (tier != "claude" && (fb.Count == 0 || fb[^1] != FallbackTier))
            fb.Add(FallbackTier);

        if (fb.Count > 0)
            fallbacks[tier] = fb;
    }

    return (aliases, fallbacks);
}

/// <summary>Resolves the required env-var key for a model name,
/// merging <see cref="ModelToKey"/> and <see cref="ModelToRequiredKey"/>.</summary>
private static string GetRequiredKey(string model)
{
    if (model == "fallback") return "HF_TOKEN";
    if (ModelToKey.TryGetValue(model, out var key)) return key;
    if (ModelToRequiredKey.TryGetValue(model, out var extra)) return extra;
    return "HF_TOKEN"; // defensive: unknown models default to HF floor
}

